mapper.select:
SELECT sl.id, sl.title, sl.request_url, sl.operate_param AS params, sl.json_result, sl.status, sl.error_msg, sl.response_time, sl.platform, sl.create_time, su.mobile operator FROM sys_log sl LEFT JOIN sys_user su on su.id = sl.user_id
AND su.mobile = #{query.operator}
AND sl.title LIKE CONCAT('%',#{query.title},'%')
AND sl.create_time BETWEEN #{query.startTime} AND #{query.endTime}
